function App() {
  const [leftFoot, setLeftFoot] = useState(null);
  const [rightFoot, setRightFoot] = useState(null);

  useEffect(() => {


    const leftRef = ref(db, "leftFoot");
    const rightRef = ref(db, "rightFoot");

    const unsubscribeLeft = onValue(leftRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const entries = Object.values(data);
        const latest = entries[entries.length - 1]; // latest entry
        setLeftFoot(latest);
      } else {
        setLeftFoot(null);
      }
    });

    const unsubscribeRight = onValue(rightRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const entries = Object.values(data);
        const latest = entries[entries.length - 1];
        setRightFoot(latest);
      } else {
        setRightFoot(null);
      }
    });

    // Cleanup subscriptions on unmount
    return () => {
      unsubscribeLeft();
      unsubscribeRight();
    };
  }, []);

  const renderFootData = (footData, label) => {
    if (!footData) return <p>{label}: No data available</p>;

    return (
      <div style={{ marginBottom: 20 }}>
        <h2>{label}</h2>
        <p><strong>Timestamp:</strong> {footData.timestamp}</p>
        <p><strong>Force:</strong> {footData.force} N</p>
        <h4>Accelerometer</h4>
        <ul>
          <li>X: {footData.accel?.x}</li>
          <li>Y: {footData.accel?.y}</li>
          <li>Z: {footData.accel?.z}</li>
        </ul>
        <h4>Gyroscope</h4>
        <ul>
          <li>X: {footData.gyro?.x}</li>
          <li>Y: {footData.gyro?.y}</li>
          <li>Z: {footData.gyro?.z}</li>
        </ul>
      </div>
    );
  };

  return (
    <div style={{ padding: 20, fontFamily: "Arial, sans-serif" }}>
      <h1>Latest Foot Sensor Data</h1>
      {renderFootData(leftFoot, "Left Foot")}
      {renderFootData(rightFoot, "Right Foot")}
    </div>
  );
}

export default App;
